")\n  /// JSON: string[] — id игроков для тестовой рассылки\n  testPlayerIds   Json     @default(\"[]\") @map(\"test_player_ids\")\n  updatedAt       DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"notification_global_config\")\n}\n\n/// Настройки по типу уведомления (id из NOTIFICATION_CATALOG).\nmodel NotificationTypeConfig {\n  notificationId   String   @id @map(\"notification_id\")\n  enabled          Boolean  @default(true)\n  templateOverride String?  @map(\"template_override\") @db.Text\n  updatedAt        DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"notification_type_config\")\n}\n\n/// Вкл/выкл типа сетки (код = TournamentFormat, реестр BRACKET_FORMAT_CATALOG).\nmodel BracketFormatConfig {\n  formatCode       String   @id @map(\"format_code\")\n  enabled          Boolean  @default(true)\n  /// Техобслуживание: тип виден в админке, но недоступен при создании турнира\n  maintenanceMode  Boolean  @default(false) @map(\"maintenance_mode\")\n  /// Скрыт из списка «Типы сеток» в админке (турниры с форматом остаются)\n  hiddenInAdmin    Boolean  @default(false) @map(\"hidden_in_admin\")\n  /// Переопределение лимита участников (null — значение по умолчанию для формата)\n  participantMin   Int?     @map(\"participant_min\")\n  participantMax   Int?     @map(\"participant_max\")\n  participantExact Int?     @map(\"participant_exact\")\n  /// null — брать из BRACKET_FORMAT_CATALOG; иначе переопределение «эталон»\n  isReference      Boolean? @map(\"is_reference\")\n  updatedAt        DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"bracket_format_config\")\n}\n\n/// Значения по умолчанию при создании турнира (одна строка, /admin/handicap).\nmodel TournamentDefaultsConfig {\n  id               String                 @id @default(\"default\")\n  handicapHalfStep Boolean                @default(true) @map(\"handicap_half_step\")\n  limitByRating    Boolean                @default(true) @map(\"limit_by_rating\")\n  ratingMax        Float?                 @map(\"rating_max\")\n  ratingSource     TournamentRatingSource @default(CLUB) @map(\"rating_source\")\n  updatedAt        DateTime               @updatedAt @map(\"updated_at\")\n\n  @@map(\"tournament_defaults_config\")\n}\n\n/// Журнал отправок Telegram: каждая попытка (успех / ошибка / пропуск с причиной).\nmodel TelegramDeliveryLog {\n  id             String   @id @default(cuid())\n  notificationId String?  @map(\"notification_id\")\n  context        String\n  status         String\n  chatId         String?  @map(\"chat_id\")\n  playerId       String?  @map(\"player_id\")\n  entityType     String?  @map(\"entity_type\")\n  entityId       String?  @map(\"entity_id\")\n  batchId        String?  @map(\"batch_id\")\n  skipReason     String?  @map(\"skip_reason\") @db.VarChar(512)\n  errorMessage   String?  @map(\"error_message\") @db.VarChar(512)\n  messagePreview String?  @map(\"message_preview\") @db.VarChar(500)\n  createdAt      DateTime @default(now()) @map(\"created_at\")\n\n  @@index([notificationId, createdAt])\n  @@index([entityType, entityId, createdAt])\n  @@index([batchId])\n  @@index([status, createdAt])\n  @@index([createdAt])\n  @@map(\"telegram_delivery_logs\")\n}\n",
